+    fn lexical_rebuild_test_source_map(
+        storage: &FrankenStorage,
+    ) -> HashMap<String, (SourceKind, Option<String>)> {
+        storage
+            .list_sources()
+            .unwrap_or_default()
+            .into_iter()
+            .map(|source| (source.id, (source.kind, source.host_label)))
+            .collect()
+    }
